```class Solution {
public:
    long long findMaximumNumber(long long k, int x) {
        long long res = 0;
        while (k > 0) {
            long long cur = (1LL << (x * (res + 1) - 1)) - 1;
            if (cur <= k) {
                res++;
                k -= cur;
            } else {
                break;
            }
        }
        return res;
    }
};```
